#include <FastLED.h>
#define NUM_LEDS 64   // 8x8 matrix
#define DATA_PIN 6
CRGB leds[NUM_LEDS];
void setup() {
  FastLED.addLeds<WS2812B, DATA_PIN, GRB>(leds, NUM_LEDS);
  FastLED.setBrightness(50); // 0-255 (start low!)
}
void loop() {
  // Rainbow animation
  for (int hue = 0; hue < 256; hue++) {
    fill_rainbow(leds, NUM_LEDS, hue, 4);
    FastLED.show();
    delay(10);
  }
}
